class JobQueue:
    """Resource-aware job queue with push-based observability (CR-6)."""

    # CR-6: per-subscriber bounded queue size. Slow subscribers backpressure
    # themselves via QueueFull drop; publisher never blocks. 100 events is
    # large enough that a UI tab pause of a few seconds doesn't drop events
    # under typical workloads, small enough that a stuck subscriber doesn't
    # accumulate unbounded memory.
    SUBSCRIBER_QUEUE_MAXSIZE: int = 100

    def __init__(
        self,
        deps: JobQueueDependencies,        # Substrate dependencies (PluginManager satisfies structurally)
        max_history: int = 100,            # Max completed jobs to retain
        cancel_timeout: float = 3.0,       # Seconds to wait for cooperative cancel
        progress_poll_interval: float = 1.0,  # Seconds between progress polls
        sysmon_plugin_name: Optional[str] = None,  # CR-3 MonitorPlugin instance for GPU stats (None = no GPU info)
        resource_snapshot_cadence_polls: int = 4,  # Sample resources every Nth progress poll
    ):
        """Initialize the job queue.

        CR-6 Stage 3 adds `sysmon_plugin_name` and `resource_snapshot_cadence_polls`.
        Sysmon integration is optional — when set, the named plugin must satisfy
        CR-3's typed `MonitorPlugin` shape (`get_system_status` + `list_processes`).
        When unset, ResourceSnapshot still carries worker stats but all GPU
        fields stay None.
        """
        self._deps = deps
        self.max_history = max_history
        self.cancel_timeout = cancel_timeout
        self.progress_poll_interval = progress_poll_interval
        self._sysmon_name = sysmon_plugin_name
        self.resource_snapshot_cadence_polls = max(1, resource_snapshot_cadence_polls)
        self.logger = logging.getLogger(f"{__name__}.{type(self).__name__}")

        # State
        self._pending: List[Job] = []  # Priority heap
        self._running: Optional[Job] = None
        self._history: List[Job] = []  # Completed/cancelled/failed jobs
        self._jobs: Dict[str, Job] = {}  # All jobs by ID for fast lookup

        # CR-6 Stage 2: sequence registry. JobSequence instances keyed by
        # sequence_id. Currently unbounded; sequence eviction is a follow-up
        # (parallel to `max_history` for terminal sequences).
        self._sequences: Dict[str, JobSequence] = {}

        # Synchronization
        self._lock = asyncio.Lock()
        self._job_available = asyncio.Event()
        self._job_completed_events: Dict[str, asyncio.Event] = {}

        # CR-6: multi-subscriber event bus.
        # Keys: "all" (firehose), "job:<id>", "seq:<id>". Each subscriber owns
        # one bounded asyncio.Queue; the publisher fans out to every matching
        # key. Independent of `_job_completed_events` (which backs the
        # `wait_for_job` simple-block affordance).
        self._subscribers: Dict[str, List[_Subscription]] = defaultdict(list)

        # Background task
        self._processor_task: Optional[asyncio.Task] = None
        self._running_flag = False
        self._cancel_requested: Set[str] = set()  # Job IDs pending cancellation

    # REMOVE-AFTER-OVERHAUL: backward-compat alias for `self.manager`. The
    # SG-13 regression test + any host inspection still expects a `.manager`
    # attribute. SG-48 sweep retires this after consumer cascade migrates
    # to the new `deps`/`_deps` shape.
    @property
    def manager(self) -> JobQueueDependencies:
        return self._deps

# %% ../../nbs/core/queue.ipynb #submission
async def _enqueue_job(
    self,
    job: Job,  # Pre-constructed Job (caller fills sequence fields if needed)
) -> str:  # job_id
    """Internal: enqueue a pre-constructed Job.

    Caller is responsible for validation (disabled-plugin check, etc.).
    Used by `submit` (Stage 1) and `submit_sequence` (Stage 2) — the latter
    needs to populate `sequence_id` + `sequence_index` on the Job before
    enqueueing so the running job appears in sequence-tagged event streams
    from its first STATE_TRANSITION.
    """
    async with self._lock:
        self._jobs[job.id] = job
        heapq.heappush(self._pending, job)
        self._job_completed_events[job.id] = asyncio.Event()
        self._job_available.set()

    seq_suffix = f" (seq {job.sequence_id[:8]} step {job.sequence_index})" if job.sequence_id else ""
    self.logger.info(
        f"Submitted job {job.id[:8]} for {job.plugin_instance_id} "
        f"(priority={job.priority}){seq_suffix}"
    )
    return job.id


async def submit(
    self,
    plugin_instance_id: str,  # Target plugin instance (per CR-10)
    *args,
    priority: int = 0,  # Higher = more urgent
    **kwargs
) -> str:  # Returns job_id
    """Submit a job to the queue.

    CR-2: rejects jobs for disabled plugins at submit time (typed
    PluginDisabledError) so the failure surface matches PluginManager.
    execute_plugin's disabled gate. Submitting to a disabled plugin would
    otherwise sit in the queue until execution, then raise — moving the
    check earlier gives operators an actionable signal immediately.

    CR-6: no STATE_TRANSITION event fires at submit because the job is
    already in `pending` state at construction — there's no transition
    to publish. The first STATE_TRANSITION fires when the processor loop
    moves the job pending → running.
    """
    # CR-2: late import to avoid pulling errors module into queue's import
    # path during library load (keeps the worker.py-via-queue.py import
    # chain minimal).
    from cjm_plugin_system.core.errors import PluginDisabledError

    meta = self._deps.get_plugin_meta(plugin_instance_id)
    if meta is not None and not meta.enabled:
        raise PluginDisabledError(plugin_instance_id)

    job = Job(
        id=str(uuid.uuid4()),
        plugin_instance_id=plugin_instance_id,
        args=args,
        kwargs=kwargs,
        priority=priority,
    )
    return await self._enqueue_job(job)

JobQueue._enqueue_job = _enqueue_job
JobQueue.submit = submit

# %% ../../nbs/core/queue.ipynb #control
async def cancel(
    self,
    job_id: str  # Job to cancel
) -> bool:  # True if cancelled
    """Cancel a pending or running job.

    CR-6: publishes STATE_TRANSITION when a pending job moves directly to
    cancelled (no transition through running). Running-job cancellation
    publishes CANCEL_PHASE_CHANGED events from `_execute_with_cancellation`
    when Stage 4 wires the phase transitions; Stage 1 just records the
    cancel-request marker.

    Stage 2: when the cancelled job is a sequence member, `_advance_sequence`
    runs after the lock is released so the cancelled status propagates to
    the sequence registry (marks sequence cancelled, no further submission).
    Lock release is required because `_advance_sequence` may need to enqueue
    a next member in some flows; asyncio.Lock is not re-entrant.
    """
    advance_target: Optional[Job] = None
    async with self._lock:
        job = self._jobs.get(job_id)
        if not job:
            return False

        if job.status == JobStatus.pending:
            # Move directly to cancelled (job never ran)
            prev_status = job.status
            job.status = JobStatus.cancelled
            job.completed_at = datetime.now(timezone.utc)
            self._pending = [j for j in self._pending if j.id != job_id]
            heapq.heapify(self._pending)
            # SG-13: signal before moving to history so the just-cancelled job's
            # event is set before any eviction could pop it from the dict.
            self._signal_job_completed(job_id)
            self._move_to_history(job)
            self._publish_event(JobEvent(
                type=JobEventType.STATE_TRANSITION,
                job_id=job.id,
                plugin_instance_id=job.plugin_instance_id,
                sequence_id=job.sequence_id,
                sequence_index=job.sequence_index,
                payload={"from": prev_status.value, "to": job.status.value},
            ))
            self.logger.info(f"Cancelled pending job {job_id[:8]}")
            if job.sequence_id is not None:
                advance_target = job

        elif job.status == JobStatus.running:
            # Signal cancellation request; phase-transition events (Stage 4)
            # fire from `_execute_with_cancellation` as cooperative → force
            # → reloading → completed unfolds. Sequence advance for a
            # running cancelled job happens from `_execute_job`'s finalization
            # path once the cancel resolves.
            self._cancel_requested.add(job_id)
            job.cancel_requested_at = datetime.now(timezone.utc)
            self.logger.info(f"Cancellation requested for running job {job_id[:8]}")
            return True

        else:
            return False  # Already completed/cancelled/failed

    # Outside the lock — safe to call _advance_sequence which may enqueue
    # follow-on work (no follow-on for cancelled members, but the invariant
    # is preserved for code symmetry with the running-job advance path).
    if advance_target is not None:
        await self._advance_sequence(advance_target)
    return True


def reorder(
    self,
    job_id: str,  # Job to move
    new_priority: int  # New priority value
) -> bool:  # True if reordered
    """Change the priority of a pending job."""
    job = self._jobs.get(job_id)
    if not job or job.status != JobStatus.pending:
        return False

    job.priority = new_priority
    heapq.heapify(self._pending)
    self.logger.info(f"Reordered job {job_id[:8]} to priority {new_priority}")
    return True

JobQueue.cancel = cancel
JobQueue.reorder = reorder

# %% ../../nbs/core/queue.ipynb #observation
def get_job(
    self,
    job_id: str  # Job to retrieve
) -> Optional[Job]:  # Job or None
    """Get a job by ID."""
    return self._jobs.get(job_id)

async def wait_for_job(
    self,
    job_id: str,  # Job to wait for
    timeout: Optional[float] = None  # Max seconds to wait
) -> Job:  # Completed/failed/cancelled job
    """Wait for a job to complete.

    Independent of the CR-6 event bus — uses a per-job `asyncio.Event` for
    the simple block-until-done affordance. Streaming consumers should use
    `events(job_id)` instead.
    """
    event = self._job_completed_events.get(job_id)
    if not event:
        job = self._jobs.get(job_id)
        if job and job.status in (JobStatus.completed, JobStatus.failed, JobStatus.cancelled):
            return job
        raise ValueError(f"Unknown job: {job_id}")

    try:
        await asyncio.wait_for(event.wait(), timeout=timeout)
    except asyncio.TimeoutError:
        raise TimeoutError(f"Timeout waiting for job {job_id}")

    return self._jobs[job_id]

def get_pending(self) -> List[Job]:  # Pending jobs, priority-sorted
    """Get pending jobs, priority-sorted (higher priority first, then FIFO)."""
    return sorted(self._pending)

def get_running(self) -> Optional[Job]:  # Running job or None
    """Get the currently-executing job, or None if idle."""
    return self._running

def get_history(
    self,
    limit: Optional[int] = None,  # Max jobs to return (most recent N); None = all
) -> List[Job]:  # Completed/failed/cancelled jobs, most recent first
    """Get completed jobs, most recent first.

    If `limit` is provided, returns the most recent N. The internal history
    list grows append-only up to `max_history`, so older jobs are evicted
    in submission order (oldest first).
    """
    history = self._history if limit is None else self._history[-limit:]
    return list(reversed(history))

def get_stats(self) -> QueueStats:  # Aggregate counts
    """Get aggregate queue stats — total counts by terminal status."""
    return QueueStats(
        total_pending=len(self._pending),
        total_completed=sum(1 for j in self._history if j.status == JobStatus.completed),
        total_failed=sum(1 for j in self._history if j.status == JobStatus.failed),
        total_cancelled=sum(1 for j in self._history if j.status == JobStatus.cancelled),
    )

# CR-6 Stage 3: log-slicing helpers. Worker log format from `worker.py`
# `basicConfig`: `%(asctime)s [%(levelname)s] %(message)s`. Default asctime
# emits local-time with millisecond precision: `YYYY-MM-DD HH:MM:SS,mmm`.
import re as _re_logslice
_LOG_TS_PATTERN = _re_logslice.compile(r'^(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}),(\d{3})\s')


def _parse_log_timestamp(line: str) -> Optional[datetime]:
    """Parse the leading timestamp from a worker log line.

    Returns naive datetime (no tzinfo) in local time — caller is responsible
    for tz alignment with the job's UTC timestamps. Returns None for
    continuation lines (no parseable leading timestamp), blank lines, etc.
    """
    m = _LOG_TS_PATTERN.match(line)
    if not m:
        return None
    try:
        dt = datetime.strptime(m.group(1), "%Y-%m-%d %H:%M:%S")
        return dt.replace(microsecond=int(m.group(2)) * 1000)
    except ValueError:
        return None


def _slice_log_by_job_window(
    raw: str,  # Full log content
    started_at: datetime,  # Job's UTC start time
    completed_at: Optional[datetime],  # Job's UTC end time (None if still running)
    max_lines: int,  # Max lines to return
) -> str:  # Sliced log content
    """Slice log content by a job's execution window.

    Worker logs are local-time naive; job timestamps are UTC. We convert
    the job's UTC times to local-time-naive for comparison. Continuation
    lines (no parseable timestamp) are associated with the most recent
    timestamped line — included if that timestamp was in the window.

    Best-effort: if `started_at` is None (job never ran) or no lines have
    parseable timestamps, returns the raw tail unchanged.
    """
    if started_at is None:
        return '\n'.join(raw.split('\n')[-max_lines:])

    start_naive = started_at.astimezone().replace(tzinfo=None)
    end_naive = (
        completed_at.astimezone().replace(tzinfo=None)
        if completed_at is not None else None
    )

    in_window = False
    selected: List[str] = []
    saw_timestamp = False
    for line in raw.split('\n'):
        ts = _parse_log_timestamp(line)
        if ts is not None:
            saw_timestamp = True
            if ts < start_naive:
                in_window = False
            elif end_naive is not None and ts > end_naive:
                in_window = False
            else:
                in_window = True
        if in_window:
            selected.append(line)

    # If no timestamps were parseable in the raw log, fall back to the raw tail
    # rather than returning empty (heuristic preservation of useful content).
    if not saw_timestamp:
        return '\n'.join(raw.split('\n')[-max_lines:])

    return '\n'.join(selected[-max_lines:])


def get_job_logs(
    self,
    job_id: str,  # Job to get logs for
    lines: int = 100  # Max lines to return
) -> str:  # Log content scoped to this job's execution window
    """Get logs for a job, scoped to its (started_at, completed_at) window.

    CR-6 Stage 3: replaces the legacy whole-plugin-log behavior. The
    substrate over-fetches the plugin log (lines * 5) and slices by the
    job's execution window — the job-monitor library's `--- Starting` marker
    heuristic in `_filter_current_session` becomes obsolete in cascade.

    Falls back gracefully when timestamps are unparseable or the job's
    window isn't known: returns the raw tail.
    """
    job = self._jobs.get(job_id)
    if not job:
        return ""

    # Over-fetch: continuation lines + lines outside the window get filtered,
    # so we need enough raw content to populate `lines` results post-slice.
    raw = self._deps.get_plugin_logs(job.plugin_instance_id, lines=lines * 5)

    if job.started_at is None:
        # Job hasn't run yet — no useful slice. Return raw tail.
        return '\n'.join(raw.split('\n')[-lines:])

    return _slice_log_by_job_window(raw, job.started_at, job.completed_at, lines)

JobQueue.get_job = get_job
