async def submit_sequence(
    self,
    steps: List[SequenceStep],  # Sequence steps to run in order
    priority: int = 0,          # Sequence-level priority (per-step override possible)
    fail_fast: bool = True,     # Halt on first failure (audit-locked default)
) -> str:  # sequence_id
    """Submit a multi-step job sequence (CR-6 Stage 2).

    Validates all step plugins upfront (`PluginDisabledError` if any are
    disabled) so operators get an immediate failure signal rather than
    discovering the problem mid-sequence. The first member-job is tagged
    with sequence fields BEFORE enqueue, so its first STATE_TRANSITION
    already routes through sequence-tagged subscribers.

    Returns the sequence_id; consumers subscribe via
    `queue.events_for_sequence(sequence_id)` or query state via
    `queue.get_sequence(sequence_id)`.
    """
    from cjm_plugin_system.core.errors import PluginDisabledError

    # Empty sequence — return a completed-at-submit sequence_id so the API
    # is total. Edge case; consumers can avoid by not submitting empty lists.
    if not steps:
        seq_id = str(uuid.uuid4())
        seq = JobSequence(
            id=seq_id, steps=[], fail_fast=fail_fast, priority=priority,
            status=JobStatus.completed,
            completed_at=datetime.now(timezone.utc),
        )
        self._sequences[seq_id] = seq
        self.logger.info(f"Submitted empty sequence {seq_id[:8]} (immediately completed)")
        return seq_id

    # Validate all steps upfront. Fail with the first offending step's
    # plugin name; operator can correlate via the step index in the log.
    for i, step in enumerate(steps):
        meta = self._deps.get_plugin_meta(step.plugin_instance_id)
        if meta is not None and not meta.enabled:
            self.logger.error(
                f"Sequence submission rejected: step {i} targets disabled "
                f"plugin {step.plugin_instance_id}"
            )
            raise PluginDisabledError(step.plugin_instance_id)

    seq_id = str(uuid.uuid4())
    seq = JobSequence(
        id=seq_id, steps=list(steps), fail_fast=fail_fast, priority=priority,
        status=JobStatus.running,
    )
    self._sequences[seq_id] = seq

    # Build + enqueue first member with sequence fields populated.
    first = steps[0]
    first_job = Job(
        id=str(uuid.uuid4()),
        plugin_instance_id=first.plugin_instance_id,
        args=first.args,
        kwargs=dict(first.kwargs),
        priority=first.priority if first.priority else priority,
        sequence_id=seq_id,
        sequence_index=0,
    )
    seq.current_job_id = first_job.id
    await self._enqueue_job(first_job)

    self.logger.info(
        f"Submitted sequence {seq_id[:8]} ({len(steps)} steps, "
        f"fail_fast={fail_fast}, priority={priority})"
    )
    return seq_id


async def submit_uniform_sequence(
    self,
    plugin_instance_id: str,  # Plugin every step targets
    args_list: List[Tuple[Any, ...]],  # Per-step positional args
    kwargs_list: Optional[List[Dict[str, Any]]] = None,  # Per-step keyword args (default: empty)
    priority: int = 0,        # Sequence-level priority
    fail_fast: bool = True,   # Halt on first failure (audit-locked default)
) -> str:  # sequence_id
    """Submit a sequence where every step targets the same plugin (CR-6 Stage 2).

    Sugar over `submit_sequence` for the common "same plugin, many arg sets"
    case — multi-source transcription / batch processing / parameter sweeps.
    """
    if kwargs_list is None:
        kwargs_list = [{} for _ in args_list]
    if len(args_list) != len(kwargs_list):
        raise ValueError(
            f"args_list and kwargs_list must have same length "
            f"({len(args_list)} vs {len(kwargs_list)})"
        )

    steps = [
        SequenceStep(
            plugin_instance_id=plugin_instance_id,
            args=tuple(args),
            kwargs=dict(kwargs),
        )
        for args, kwargs in zip(args_list, kwargs_list)
    ]
    return await self.submit_sequence(steps, priority=priority, fail_fast=fail_fast)


async def cancel_sequence(
    self,
    sequence_id: str  # Sequence to cancel
) -> bool:  # True if cancellation was recorded
    """Cancel an in-flight sequence (CR-6 Stage 2).

    Marks the sequence as cancelled (no further advancement) and cancels
    the current member job. Returns False if the sequence is unknown or
    already terminal; True if cancellation was recorded.

    Sets `seq.status = JobStatus.cancelled` BEFORE issuing the member-job
    cancel. This prevents a race where the member completes between the
    intent record and the cancel call — `_advance_sequence` checks
    `seq.status == cancelled` first and halts regardless of member outcome.
    """
    seq = self._sequences.get(sequence_id)
    if seq is None or seq.status != JobStatus.running:
        return False

    seq.status = JobStatus.cancelled
    self.logger.info(f"Cancellation requested for sequence {sequence_id[:8]}")

    current_id = seq.current_job_id
    if current_id and current_id in self._jobs:
        current_job = self._jobs[current_id]
        if current_job.status in (JobStatus.pending, JobStatus.running):
            await self.cancel(current_id)
            # `cancel()` runs _advance_sequence after release; that path
            # sees status==cancelled and finalizes the sequence (sets
            # completed_at).
            return True

    # No active member to cancel (between-steps state) — finalize now.
    seq.completed_at = datetime.now(timezone.utc)
    seq.current_job_id = None
    return True


def get_sequence(
    self,
    sequence_id: str  # Sequence to retrieve
) -> Optional[JobSequence]:  # JobSequence or None
    """Get a job sequence by ID (read-only inspection)."""
    return self._sequences.get(sequence_id)


async def _advance_sequence(
    self,
    completed_job: Job  # The member job that just reached terminal status
) -> None:
    """Advance the sequence after a member job completes (CR-6 Stage 2).

    Records the member's StepResult, decides whether to advance / halt /
    finalize, and submits the next member if applicable. Always called
    OUTSIDE the queue's main lock — may take it via `_enqueue_job`.
    """
    seq = self._sequences.get(completed_job.sequence_id)
    if seq is None:
        # Sequence already cleaned up; nothing to do.
        return

    # Record this member's outcome. completed/failed/cancelled are the only
    # terminal statuses this path sees.
    member_status = completed_job.status
    step_result = StepResult(
        job_id=completed_job.id,
        success=(member_status == JobStatus.completed),
        result=completed_job.result if member_status == JobStatus.completed else None,
        error=completed_job.error,
    )
    seq.results.append(step_result)

    # 1. Sequence-level cancel intent (cancel_sequence was called):
    #    halt regardless of member-job outcome.
    # 2. Member was cancelled (direct or via cancel_sequence cascade):
    #    halt the sequence (cancellation always halts).
    # 3. Member failed + fail_fast=True: halt with failed status.
    # 4. Member failed + fail_fast=False: continue to next step.
    # 5. Member succeeded: continue to next step.
    if seq.status == JobStatus.cancelled or member_status == JobStatus.cancelled:
        seq.status = JobStatus.cancelled
        seq.completed_at = datetime.now(timezone.utc)
        seq.current_job_id = None
        self.logger.info(
            f"Sequence {seq.id[:8]} cancelled (member {completed_job.id[:8]} "
            f"status={member_status.value})"
        )
        return

    if member_status == JobStatus.failed and seq.fail_fast:
        seq.status = JobStatus.failed
        seq.completed_at = datetime.now(timezone.utc)
        seq.current_job_id = None
        self.logger.info(
            f"Sequence {seq.id[:8]} failed (fail_fast, step {seq.current_index})"
        )
        return

    # Advance to the next step
    seq.current_index += 1
    if seq.current_index >= len(seq.steps):
        # All steps attempted (may include failures if fail_fast=False)
        any_failures = any(not r.success for r in seq.results)
        seq.status = JobStatus.failed if (any_failures and seq.fail_fast) else JobStatus.completed
        # NOTE: fail_fast=False sequences land as `completed` even with failed
        # members; the results list captures the per-step outcomes. This
        # matches "best-effort" semantics — "we attempted everything".
        seq.completed_at = datetime.now(timezone.utc)
        seq.current_job_id = None
        self.logger.info(
            f"Sequence {seq.id[:8]} completed ({len(seq.steps)} steps, "
            f"{sum(1 for r in seq.results if r.success)} succeeded)"
        )
        return

    # Submit next member
    next_step = seq.steps[seq.current_index]
    next_job = Job(
        id=str(uuid.uuid4()),
        plugin_instance_id=next_step.plugin_instance_id,
        args=next_step.args,
        kwargs=dict(next_step.kwargs),
        priority=next_step.priority if next_step.priority else seq.priority,
        sequence_id=seq.id,
        sequence_index=seq.current_index,
    )
    seq.current_job_id = next_job.id
    await self._enqueue_job(next_job)

    # Emit SEQUENCE_ADVANCED so sequence subscribers see the transition
    # between member jobs as a discrete signal (in addition to the next
    # member's STATE_TRANSITION pending → running fire when it starts).
    self._publish_event(JobEvent(
        type=JobEventType.SEQUENCE_ADVANCED,
        job_id=next_job.id,
        plugin_instance_id=next_job.plugin_instance_id,
        sequence_id=seq.id,
        sequence_index=seq.current_index,
        payload={
            "prior_job_id": completed_job.id,
            "prior_step_index": seq.current_index - 1,
            "prior_success": step_result.success,
        },
    ))


JobQueue.submit_sequence = submit_sequence
